	Style.prototype.toXml = function()
	{
		var item = null;
		var key = null;
		var attributes = {};
		for(key in this.__objProp)
		{
			item = this.__objProp[key];
			if(!this.util.isUndefinedOrNull(item.value))
			{
				if(item.className)
				{
					this.__children.push(item.value);
				}
				else if(item.isEmpty)
				{
					this.__children.push("<w:" + key + "/>");
				}
				else
				{
					this.__children.push(this.__exportUtil.getValXml(item.value,"w:" + key));
				}
			}
		}
		for(key in this.__objAttr)
		{
			item = this.__objAttr[key];
			if(!this.util.isUndefinedOrNull(item.value))
			{
				attributes["w:" + key] = item.value;
			}
		}
		if(this.__children && this.__children.length)
		{
			var xml = this.base.toXml.call(this,"w:style",attributes);
			return xml;
		}
		return null;
	};
	
