	ParagraphFormat.prototype.setProperties = function(option)
	{
		if(option)
		{
			if (option.horizontalAlign) 
			{
                this.horizontalAlignment(option.horizontalAlign);
            }
			if(option.borders) 
            {
				this.borders(option.borders)
            }
			else if (option.horizontalLine) 
            {
                this.horizontalLine();
            }
            if (option.contextualSpacing) 
            {
                this.contextualSpacing(option.contextualSpacing);
            }
            if (option.rightTab) 
            {
            	var tabs = this.tabs();
            	tabs.addTab({val: "right",pos: option.rightTab});
            }
            if (option.leftTab) 
            {
            	var tabs = this.tabs();
            	tabs.addTab({val: "left",pos: option.leftTab});
            }
            if (option.indent) 
            {
                this.indentation(option.indent);
            }
            if (option.spacing) 
            {
                this.spacing(option.spacing);
            }
            if (option.keepNext) 
            {
                this.keepNext(true);
            }
            if (option.keepLines) 
            {
            	this.keepLines(true);
            }
            if (option.outlineLevel) 
            {
                this.outlineLevel(option.outlineLevel);
            }
            if (option.styleID) 
            {
                this.styleID(option.styleID);
            }
            if (option.numberingProperties) 
            {
            	this.numberingProperties(option.numberingProperties);
            }
		}
	};
	
